solution:
function findAnagrams(s, p) {
  const res = [];
  if (p.length > s.length) return res;
  const need = new Map();
  for (let i = 0; i < p.length; i++) need.set(p[i], (need.get(p[i]) || 0) + 1);
  const win = new Map();
  const k = p.length;
  const eq = (a, b) => {
    if (a.size !== b.size) return false;
    for (const [key, v] of a) if (b.get(key) !== v) return false;
    return true;
  };
  for (let right = 0; right < s.length; right++) {
    const c = s[right];
    win.set(c, (win.get(c) || 0) + 1);
    if (right >= k) {
      const lc = s[right - k];
      win.set(lc, win.get(lc) - 1);
      if (win.get(lc) === 0) win.delete(lc);
    }
    if (right >= k - 1 && eq(win, need)) res.push(right - k + 1);
  }
  return res;
}

