function minWindow(s, t) {
  // your code here
}

solution:
function minWindow(s, t) {
  if (t.length === 0 || s.length < t.length) return '';
  const need = new Map();
  for (let i = 0; i < t.length; i++) need.set(t[i], (need.get(t[i]) || 0) + 1);
  let missing = t.length;
  let left = 0, bestL = 0, bestLen = Infinity;
  for (let right = 0; right < s.length; right++) {
    const c = s[right];
    if ((need.get(c) || 0) > 0) missing--;
    need.set(c, (need.get(c) || 0) - 1);
    while (missing === 0) {
      if (right - left + 1 < bestLen) { bestLen = right - left + 1; bestL = left; }
      const lc = s[left];
      need.set(lc, need.get(lc) + 1);
      if (need.get(lc) > 0) missing++;
      left++;
    }
  }
  return bestLen === Infinity ? '' : s.slice(bestL, bestL + bestLen);
}

tests:
if (minWindow('ADOBECODEBANC', 'ABC') !== 'BANC') throw new Error(minWindow('ADOBECODEBANC', 'ABC'));
if (minWindow('a', 'a') !== 'a') throw new Error('single');
if (minWindow('a', 'aa') !== '') throw new Error('none');
if (minWindow('ab', 'b') !== 'b') throw new Error('tail');
